impl Solution { pub fn count_pairs(nums: Vec<i32>) -> i32 { let mut black_ans = 0; for i in 0..nums.len() { for j in i + 1..nums.len() { let (mut s1, mut s2) = (format!("{:07}", nums[i]).into_bytes(), format!("{:07}", nums[j]).into_bytes()); if s1 == s2 { black_ans += 1; continue; } let mut diff: Vec<usize> = (0..7).filter(|&k| s1[k] != s2[k]).collect(); if diff.len() == 2 { let (a, b) = (diff[0], diff[1]); s1.swap(a, b); if s1 == s2 { black_ans += 1; continue; } s1.swap(a, b); s2.swap(a, b); if s1 == s2 { black_ans += 1; } } } } black_ans } }